import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import { ResponsiveChartContainer, BarPlot, ChartsXAxis, ChartsYAxis, ChartsClipPath } from '@mui/x-charts';
import response from './response.json';

interface WeeklyActivity {
  day: string;
  activity: number;
}

interface FitnessData {
  dailyOverview: {
    steps: number;
    caloriesBurned: number;
  };
  weeklyActivity: WeeklyActivity[];
}

export default function Widget() {
  const fitnessData = response.data as FitnessData;
  const clipPathId = useId();

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 500, bgcolor: '#F5F7FA' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="body2" color="text.secondary">
              Daily Overview
            </Typography>
            <Typography variant="h4" fontWeight={700} sx={{ color: '#4CAF50' }}>
              {fitnessData.dailyOverview.steps.toLocaleString()} steps
            </Typography>
            <Typography variant="body2" color="text.secondary" sx={{ mt: 0.5 }}>
              {fitnessData.dailyOverview.caloriesBurned.toLocaleString()} kcal burned
            </Typography>
          </Box>

          <Box sx={{ width: '100%', height: 200 }}>
            <ResponsiveChartContainer
              series={[
                {
                  type: 'bar',
                  data: fitnessData.weeklyActivity.map(w => w.activity),
                  color: '#4CAF50',
                }
              ]}
              xAxis={[
                {
                  scaleType: 'band',
                  data: fitnessData.weeklyActivity.map(w => w.day),
                  id: 'days',
                },
              ]}
              yAxis={[{ id: 'activity' }]}
            >
              <g clipPath={`url(#${clipPathId})`}>
                <BarPlot />
              </g>
              <ChartsXAxis
                axisId="days"
                tickLabelStyle={{ fontSize: 10, fill: '#6B7280' }}
              />
              <ChartsYAxis
                axisId="activity"
                tickLabelStyle={{ fontSize: 10, fill: '#6B7280' }}
              />
              <ChartsClipPath id={clipPathId} />
            </ResponsiveChartContainer>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
